import type { Trip } from '../tables/trips';
import type { TripNode } from './types';
import { moneyExact, weekdayShort, timeOfDay, dateRange } from './format';

// Both generators are pure functions of a node's current (already-persisted)
// data — nothing is stored, so a rebook is handled for free: the next
// request just reflects the new details. The only thing that needs to stay
// stable across regenerations is the ICS UID, keyed to the node id, so a
// real calendar app treats a re-download as an update to the same event
// rather than a duplicate.

// Same "naive local" time convention every other formatter in this app uses
// (common/format.ts) — extract wall-clock components via the UTC getters and
// emit a floating (no "Z", no TZID) ICS timestamp, so it round-trips exactly
// as authored instead of being reinterpreted through a real timezone.
function icsDate(ms: number): string {
  const d = new Date(ms);
  const pad = (n: number) => String(n).padStart(2, '0');
  return `${d.getUTCFullYear()}${pad(d.getUTCMonth() + 1)}${pad(d.getUTCDate())}T${pad(d.getUTCHours())}${pad(d.getUTCMinutes())}${pad(d.getUTCSeconds())}`;
}

function icsStamp(ms: number): string {
  const d = new Date(ms);
  const pad = (n: number) => String(n).padStart(2, '0');
  return `${d.getUTCFullYear()}${pad(d.getUTCMonth() + 1)}${pad(d.getUTCDate())}T${pad(d.getUTCHours())}${pad(d.getUTCMinutes())}${pad(d.getUTCSeconds())}Z`;
}

function escapeIcsText(s: string): string {
  return s.replace(/\\/g, '\\\\').replace(/,/g, '\\,').replace(/;/g, '\\;').replace(/\n/g, '\\n');
}

function locationFor(node: TripNode): string {
  const d = node.detail || {};
  return d.address || node.location || '';
}

function descriptionFor(node: TripNode): string {
  const parts: string[] = [];
  if (node.bookingRef) parts.push(`Confirmation: ${node.bookingRef}`);
  if (node.detail?.blurb) parts.push(node.detail.blurb);
  parts.push('Generated by Waypoint.');
  return parts.join(' ');
}

export function buildIcs(node: TripNode, trip: Trip): string {
  const start = node.start ?? Date.now();
  const end = node.end ?? start + 60 * 60 * 1000;
  const lines = [
    'BEGIN:VCALENDAR',
    'VERSION:2.0',
    'PRODID:-//Waypoint//Trip Board//EN',
    'CALSCALE:GREGORIAN',
    'BEGIN:VEVENT',
    `UID:${node.id}@waypoint`,
    `DTSTAMP:${icsStamp(Date.now())}`,
    `DTSTART:${icsDate(start)}`,
    `DTEND:${icsDate(end)}`,
    `SUMMARY:${escapeIcsText(node.title)}`,
    `LOCATION:${escapeIcsText(locationFor(node))}`,
    `DESCRIPTION:${escapeIcsText(descriptionFor(node))}`,
    'SEQUENCE:0',
    'END:VEVENT',
    'END:VCALENDAR',
  ];
  return lines.join('\r\n');
}

function walletFieldsFlight(node: TripNode): string {
  const d = node.detail || {};
  return `
    <div class="wp-pass-row"><span>Flight</span><strong>${escapeHtml(`${d.carrier || ''} ${d.flightNumber || ''}`.trim())}</strong></div>
    <div class="wp-pass-row"><span>Route</span><strong>${escapeHtml(node.title)}</strong></div>
    <div class="wp-pass-row"><span>Departs</span><strong>${node.start ? escapeHtml(`${weekdayShort(node.start)}, ${timeOfDay(node.start)}`) : '—'}</strong></div>
    <div class="wp-pass-row"><span>Arrives</span><strong>${node.end ? escapeHtml(timeOfDay(node.end)) : '—'}</strong></div>
    <div class="wp-pass-row"><span>Confirmation</span><strong>${escapeHtml(node.bookingRef || '—')}</strong></div>`;
}

function walletFieldsGeneric(node: TripNode): string {
  const d = node.detail || {};
  return `
    <div class="wp-pass-row"><span>${node.kind === 'hotel' ? 'Hotel' : 'Activity'}</span><strong>${escapeHtml(node.title)}</strong></div>
    <div class="wp-pass-row"><span>When</span><strong>${escapeHtml(dateRange(node.start, node.end) || '—')}</strong></div>
    <div class="wp-pass-row"><span>Where</span><strong>${escapeHtml(locationFor(node) || '—')}</strong></div>
    <div class="wp-pass-row"><span>Confirmation</span><strong>${escapeHtml(node.bookingRef || '—')}</strong></div>
    ${node.costCents != null ? `<div class="wp-pass-row"><span>Cost</span><strong>${escapeHtml(moneyExact(node.costCents))}</strong></div>` : ''}`;
}

function escapeHtml(s: string): string {
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

// A styled standalone preview page — NOT a real installable .pkpass/Google
// Wallet object. There's no Apple Developer Pass Type ID certificate or
// Google Wallet issuer approval behind this app, so this is honestly labeled
// as a preview rather than pretending to be something it isn't.
export function buildWalletPreview(node: TripNode, trip: Trip): string {
  const fields = node.kind === 'flight' ? walletFieldsFlight(node) : walletFieldsGeneric(node);
  return `<!doctype html>
<html>
<head>
<meta charset="utf-8">
<title>${escapeHtml(node.title)} — Wallet preview</title>
<style>
  body { margin: 0; padding: 40px 20px; background: #f2f0eb; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; display: flex; flex-direction: column; align-items: center; }
  .wp-pass-badge { font-size: 12px; color: #8a8578; margin-bottom: 16px; letter-spacing: 0.02em; text-transform: uppercase; }
  .wp-pass { width: 100%; max-width: 380px; background: #1c1c1e; color: #fff; border-radius: 20px; padding: 24px; box-shadow: 0 12px 30px rgba(0,0,0,0.25); }
  .wp-pass-kind { font-size: 13px; opacity: 0.6; margin-bottom: 4px; }
  .wp-pass-title { font-size: 20px; font-weight: 600; margin-bottom: 20px; }
  .wp-pass-row { display: flex; justify-content: space-between; gap: 12px; padding: 10px 0; border-top: 1px solid rgba(255,255,255,0.12); font-size: 14px; }
  .wp-pass-row span { opacity: 0.6; }
  .wp-pass-foot { margin-top: 24px; font-size: 11px; color: #b2ac9c; text-align: center; max-width: 380px; }
</style>
</head>
<body>
  <div class="wp-pass-badge">Preview — not a real installable Wallet pass yet</div>
  <div class="wp-pass">
    <div class="wp-pass-kind">${escapeHtml(trip.title)}</div>
    <div class="wp-pass-title">${escapeHtml(node.title)}</div>
    ${fields}
  </div>
  <div class="wp-pass-foot">Real Apple Wallet / Google Wallet passes need a signed Pass Type ID and an approved Wallet issuer account — this is a preview of what one would show.</div>
</body>
</html>`;
}
